;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2]

;-------------------------------------------------------------------------------
*event_1
;[exp] party.lastIsMove

[texton]
[name n=Devil f=imp_00]「Hey, you guys! Are you really planning to go down into this cave?」[k]
[name n=Devil f=imp_00]「You'd better stop! There are tons of terrifying demons down there! You won't make it back alive!」[k]
[textoff]

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] party.lastIsMove

[texton]
[name n=Devil f=succubus_10]「Would you like to purchase something?」[k]
[textoff]

@question title="Take a look?"
[eventoff cond='! tf.result']

@shop name=大人の魔法店

[texton]
[if exp='o.大人の魔法店.selection.has(o.リペアの魔法書)']
	[name n=Devil f=succubus_10]「Come back again! [はーと] Hehehe!」[k]
[else]
	[name n=Devil f=succubus_10]「Do you have any worm venom?」[k]
	[name n=Devil f=succubus_10]「If you give me some worm venom, I'll sell you a good spellbook [はーと].」[k]
[endif]
[textoff]

[eventoff]
;===============================================================================
